var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"DOEHYUN_NPC_NULL_NULL","text":{"KOREA":"크윽!","JPN":"くうっ！","ENG":"Hngh!","TWN":"咳咳！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DOEHYUN_NPC_NULL_NULL","text":{"KOREA":"이 따위 총탄이 카운터에게 먹힐 거라고 생각한다면 착각...... 응?","JPN":"普通の銃弾がカウンターに効くと思ったら間違い……うん？","ENG":"Did you think these stupid bullets would work on a Count—huh?","TWN":"你以為這種子彈會對制裁者有用嗎……嗯？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOEHYUN_NPC_NULL_NULL","text":{"KOREA":"뭐야, 이거? 앗, 뜨거워! 뜨겁다고!","JPN":"何だ、これ？　あっ、熱い！　熱いっ！","ENG":"What the hell? Ow! It's hot!","TWN":"這是，什麼？啊，好燙！好燙！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DOEHYUN_NPC_NULL_NULL","text":{"KOREA":"꺼, 꺼지질 않잖아? 흐아악!","JPN":"火が、き、消えない？　うわぁ！","ENG":"Why won't it snuff out?! Aaack!","TWN":"為什麼熄不滅？啊啊啊啊！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"백린탄이라는 거다.","JPN":"白燐弾というものだ。","ENG":"It's called white phosphorous.","TWN":"那是白磷彈。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"총알을 튕겨낼 수 있다고 겁도 없이 들이대는 카운터 놈들에게 세상의 뜨거움을 느끼게 해 주는 마법의 가루지.","JPN":"弾を弾き返せると無鉄砲にかかってくるカウンター連中に、傲慢の熱さを思い知らせてやる魔法の粉だ。","ENG":"The magic powder to teach a lesson to Counters like you, who think you're invincible just because you're bulletproof.","TWN":"這種粉末會讓你們這些不怕子彈的制裁者感受被灼燒的恐懼。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"털어내려고 하면 손까지 타 버리니 얌전히 있어.","JPN":"払おうとすると手まで焼けてしまうから、大人しくしてろ。","ENG":"It'll just burn your fingers if you try to brush it off, so I'd stay put if I were you.","TWN":"別想用手擦掉，連你的手都會被燒傷哦。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DOEHYUN_NPC_NULL_NULL","text":{"KOREA":"이, 이 ■끼들이 비겁하게 이따위 무기를 써?!","JPN":"このクソ野郎どもが……卑怯にもこんな武器を使うのか！？","ENG":"You bunch of cheats! This isn't fair!","TWN":"竟然使用如此卑鄙的武器？！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOEHYUN_NPC_NULL_NULL","text":{"KOREA":"크악......","JPN":"ぐあっ……","ENG":"Ack...","TWN":"啊啊……"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"비겁하다고?","JPN":"卑怯だと？","ENG":"Not fair?","TWN":"卑鄙？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"맨몸인 사람들을 상대로 화살로 괴롭힐 땐 그런 걸 느끼지 못했나 보지?","JPN":"それは生身の人間をボウガンで一方的に苦しめた奴に当てはまる言葉だろう？","ENG":"Did you think it was fair when you tortured innocent people with your crossbow?","TWN":"你用弩弓欺負赤手空拳的普通人時就不覺得自己卑鄙嗎？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"지옥에 떨어져서 평생 피해자들에게 속죄하며 살아라. 이 쓰레기야.","JPN":"地獄に落ちて一生被害者に償い続けろ。このクズ野郎。","ENG":"Think about that as you rot in hell, you scumbag.","TWN":"掉入無底的地獄，向犧牲者們懺悔吧，你這個廢物。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DOEHYUN_NPC_NULL_NULL","text":{"KOREA":"크으으...... 머, 멈춰! 쏘지 마!","JPN":"ぐうう……ま、待て！　撃つな！","ENG":"Hngh... S-stop! Don't shoot!","TWN":"呃啊啊……不、不要！別開槍！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DOEHYUN_NPC_NULL_NULL","text":{"KOREA":"......협상, 협상을 하자! 돈이 필요한 거라면 얼마든지 줄 테니까, 응?","JPN":"……こ、交渉をしよう！　金が必要ならいくらでもやる！","ENG":"L-let's negotiate! If it's money you want, just name the price! Okay?","TWN":"……談判，我們來談判！多少錢我都給你們，怎麼樣？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"태세전환 하는 솜씨가 일품이로군.","JPN":"方針を切り替える早さだけは認めてやる。","ENG":"Oh, so now you want to negotiate?","TWN":"你這態度轉變的速度可真快。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그 돈으로 네가 죽인 희생자들이 살아날 수 있다면 고려 정도는 해 보지.","JPN":"その金であんたが殺した犠牲者たちが生き返るなら、考慮してやろう。","ENG":"Well, if that money can somehow bring back your victims from the dead, we'll give it a consideration.","TWN":"如果你可以用錢讓犧牲者們復活的話，我們會考慮考慮。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"어때, 그럴 수 있나?","JPN":"さあ、できるか？","ENG":"Think that will work?","TWN":"怎麼樣，你做得到嗎？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DOEHYUN_NPC_NULL_NULL","text":{"KOREA":"이 개자식아! 이미 죽어 버린 걸 어쩌라고?","JPN":"ふざけんなよ、クソが！　もう死んじまったんだからどうしようもないだろ！","ENG":"Of course not, you moron! They're already dead!","TWN":"狗東西！他們已經死了還怎麼復活？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DOEHYUN_NPC_NULL_NULL","text":{"KOREA":"그래서 내가 이렇게 사과를 하겠다잖아!","JPN":"だから今謝るって言ってんじゃねえか！","ENG":"That's why I'm trying to apologize here instead!","TWN":"所以我不是在道歉嗎！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그 더러운 입으로 역겨운 소리 좀 그만 지껄여!","JPN":"その腐った口で好き勝手ほざくのはいい加減にしろ！","ENG":"Shut your dirty trap, you disgusting heap of trash!","TWN":"給我閉上你那骯髒的臭嘴！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DOEHYUN_NPC_NULL_NULL","text":{"KOREA":"으아, 쏘, 쏘지 마! 제발! 우아아악!","JPN":"う、撃つな！　頼む！　うわああーっ！","ENG":"Whoa! P-please don't shoot! Please! Aaah!","TWN":"啊啊，別、別開槍！求求妳！啊啊啊啊！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"......응?","JPN":"……うん？","ENG":"Hmm?","TWN":"……嗯？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"잠깐 기다려. 이유리.","JPN":"待て、カスカベ。","ENG":"Hang on a sec, Yuri.","TWN":"等等，李悠麗。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"뭐야? 갑자기 왜?","JPN":"なに？　急になんでだよ？","ENG":"Huh? Why?","TWN":"幹嘛？怎麼了？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"저놈에게 확인할 게 생겼어.","JPN":"奴に確かめたいことがある。","ENG":"I need to check something.","TWN":"我有件事情想跟他確認。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"이봐, 비명 그만 지르고 소매 걷어 봐.","JPN":"おい、叫ぶのはそれくらいにして袖をまくってみせろ。","ENG":"Hey, stop screaming and pull up your sleeves.","TWN":"喂，別叫了，把袖子捲起來。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L37_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"이유리, 대장한테 무슨 일 생겼어?","JPN":"カスカベ、隊長になんかあったのか？","ENG":"Something happened to the Captain, Yuri?","TWN":"李悠麗，隊長怎麼了？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L38_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"나도 잘은 몰라. 갑자기 소매를 걷게 하는데...... 녀석 팔에 파란 심장 문신이 있어.","JPN":"いや、わからない。急に袖をまくらせて……奴の腕に青い心臓のタトゥーがある。","ENG":"I'm not sure. He made the guy pull up his sleeves... and there's a tattoo of a blue heart on his arm.","TWN":"不知道，他突然叫那傢伙捲起袖子……那傢伙手臂上紋著藍色的心臟。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"파란 심장 문신......?","JPN":"青い心臓のタトゥー……？","ENG":"A blue heart tattoo?","TWN":"藍色心臟紋身……？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"왜 그렇게 놀라? 뭔가 알고 있는 거야?","JPN":"それって驚くこと？　何か知ってる？","ENG":"Why do you sound so shocked? You know something I don't?","TWN":"你怎麼了？那是什麼東西？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"......이유리, 혹시 성냥팔이란 조직 이름 들어본 적 있어?","JPN":"……カスカベ、マッチ売りという組織の名前を聞いたことあるか？","ENG":"Yuri, have you heard of a crime organization called the Matchmakers?","TWN":"……李悠麗，妳有沒有聽過賣火柴組織？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L44_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"성냥팔이라면...... <color=#ffd34c>성냥</color>이라는 이름의 마약을 팔아대는 놈들이잖아.","JPN":"マッチ売りなら……<color=#ffd34c>マッチ</color>という名前の麻薬を売る連中だな。","ENG":"Matchmakers? They're the guys who sell the drugs nicknamed <color=#ffd34c>matches</color>, aren't they?","TWN":"賣火柴組織……是那些專門販賣一種叫<color=#ffd34c>火柴</color>的禁品的傢伙們吧。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"맞아. 그런데 그건 그 조직 보스의 별명이기도 하거든.","JPN":"そうだ。そしてそれは、あの組織のボスの通称でもある。","ENG":"That's right. But the Matchmaker is also the nickname for their boss.","TWN":"沒錯，而且那個組織的頭目的外號就叫賣火柴的。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"넌 모르겠지만 대장이 아주 오래 전부터 쫓고 있던 놈이지.","JPN":"お前は知らないと思うが、隊長がずっと昔から追っている奴さ。","ENG":"You may not know this, but the Captain has been after the Matchmaker for a long time.","TWN":"妳可能不知道，隊長已經追殺他很久了。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"오랫동안 흔적도 못 찾아서 겨우 포기했나 싶었는데......","JPN":"長い間痕跡すら見つからなくて、やっと諦めがついたと思っていたが……","ENG":"I figured he'd given up by now since we hadn't found any leads for a while...","TWN":"但找了很久都沒有找到他的線索，本以為隊長要放棄了……"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"네 말이 사실이라면, 방금 그 실마리를 찾아낸 것 같네.","JPN":"お前の話が事実なら、今その手がかりを見つけたようだ。","ENG":"But if what you just said is true, it sounds like he just found his lead.","TWN":"如果妳說的是真的，那他很可能找到了那個線索。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"너, 성냥팔이에 대해 얼마나 알고 있지?","JPN":"お前、マッチ売りについてどれぐらい知ってるんだ？","ENG":"What do you know about the Matchmaker?","TWN":"你應該對賣火柴組織有所瞭解吧？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DOEHYUN_NPC_NULL_NULL","text":{"KOREA":"성냥...... 팔이?","JPN":"マッチ……売り？","ENG":"Match... maker?","TWN":"賣……火柴？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"너한테 이 문신을 새기게 허락해 준 녀석 말이다.","JPN":"お前にこのタトゥーを許可してやった奴のことだ。","ENG":"I mean the guy who let you get this tattoo.","TWN":"我是說允許你在身上紋這個紋身的人。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"우연히 닮은 거라는 변명 따윈 안 통해. 나는 그 놈을 꼭 다시 한 번 만나야 하거든.","JPN":"偶然似ていただけなんて言い訳は聞かないぞ。俺はあいつに必ず会わなければならない。","ENG":"Now don't give me that crap about how this tattoo just happens to look like his. I really have to face him again, you see.","TWN":"別想騙我說是偶然之類的鬼話。我有事情必須和那傢伙見一面。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DOEHYUN_NPC_NULL_NULL","text":{"KOREA":"제...... 제발 그것만은 좀 봐 줘.","JPN":"そ……それだけは勘弁してくれ。","ENG":"P-please... anything but that.","TWN":"求你了……求求你別問我這個。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DOEHYUN_NPC_NULL_NULL","text":{"KOREA":"형님은 배신자를 절대 용서하지 않아. 무, 무슨 뜻인지 당신도 잘 알 거 아냐.","JPN":"兄貴は裏切り者を絶対に許さない。これが、ど、どういう意味なのかわかってるだろ。","ENG":"The boss never lets a snitch off. Y-you must know what that means.","TWN":"大哥不會原諒叛徒的。你，你應該知道我說的話是什麼意思吧。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"좋아. 멀리 있는 그 놈은 무섭고 나는 안 무섭단 말이군.","JPN":"ああ。この場にいない奴は怖いが、俺のことは怖くないというように聞こえるな。","ENG":"I see. So you're more scared of him, even though I'm right in front of you.","TWN":"好，你只怕他，不怕我是吧。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"유리, 저놈 입 좀 막아. 데려간다.","JPN":"カスカベ、奴の口を塞げ。連れて帰る。","ENG":"Gag him, Yuri. We'll take him with us.","TWN":"悠麗，把他的嘴巴堵住，帶走。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DOEHYUN_NPC_NULL_NULL","text":{"KOREA":"제, 제발! 다른 거라면 뭐든 말할게!","JPN":"た、頼む！　他のことなら何でもするから！","ENG":"P-please! I'll tell you anything but that!","TWN":"求、求你了！別的我都說！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOEHYUN_NPC_NULL_NULL","text":{"KOREA":"그러니까 형님 얘기만큼은......!","JPN":"だから兄貴の話だけは……！","ENG":"I can't talk about the boss!","TWN":"大哥的事情求求你別問……！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};